//@version=5
strategy("Macro + TimesFM 200M AI Oracle (GPU Edition)", overlay=true, initial_capital=10000, default_qty_type=strategy.percent_of_equity, default_qty_value=100)

// 1. Filtro Macro Global
spyClose = request.security("SPY", "D", close)
spyRet   = (spyClose - spyClose[1]) / spyClose[1]

var int daysOut = 0
if spyRet < -0.078
    daysOut := 8

// 2. Filtro Activo (V10 Subagent AI)
//@version=5
// [ADVERTENCIA] ESTA ESTRATEGIA NO SE PUEDE EJECUTAR EN TRADINGVIEW.
// TradingView y Pine Script v5 no soportan importar modelos de Redes Neuronales locales (Hugging Face / PyTorch).
// Las señales de S11 solo pueden procesarse en tu RTX 5070 local.

// Lógica de Trading Combinada
if daysOut > 0 or activeExit
    strategy.close("Long")
    if daysOut > 0
        daysOut := daysOut - 1
else
    strategy.entry("Long", strategy.long)

if barstate.isfirst
    strategy.entry("Long", strategy.long)
